package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.io.Reader;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    private URL mockUrl;
    private InputStream mockInputStream;
    private InputStreamReader mockInputStreamReader;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() throws IOException {
        mockUrl = mock(URL.class);
        mockInputStream = mock(InputStream.class);
        charset = Charset.forName("UTF-8");
        format = mock(CSVFormat.class);

        when(mockUrl.openStream()).thenReturn(mockInputStream);
    }

    @Test
    void parse_NullUrl_ThrowsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((URL)null, charset, format));
        assertEquals("url", ex.getMessage());
    }

    @Test
    void parse_NullCharset_ThrowsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockUrl, null, format));
        assertEquals("charset", ex.getMessage());
    }

    @Test
    void parse_NullFormat_ThrowsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockUrl, charset, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_ValidParameters_ReturnsCSVParser() throws IOException {
        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            // Let Assertions.notNull behave normally (do nothing)
            assertionsMockedStatic.when(() -> Assertions.notNull(any(), any())).thenAnswer(invocation -> null);

            try (MockedStatic<CSVParser> csvParserStatic = Mockito.mockStatic(CSVParser.class, Mockito.CALLS_REAL_METHODS)) {
                // Spy on constructor indirectly by mocking new InputStreamReader
                InputStreamReader reader = new InputStreamReader(mockInputStream, charset);
                CSVParser parser = new CSVParser(reader, format);

                csvParserStatic.when(() -> CSVParser.parse(mockUrl, charset, format)).thenCallRealMethod();

                CSVParser result = CSVParser.parse(mockUrl, charset, format);

                assertNotNull(result);
                assertEquals(format, result.format);
            }
        }
    }
}
